getFilteredDishes(): Dish[] {
  // 🔥 CORREZIONE SICURA: Prima filtra sempre i piatti eliminati
  let filtered = this.dishes.filter(dish => {
    const isDeleted = dish.deleted_at !== null && dish.deleted_at !== undefined;
    const isActive = dish.status === 'available';
    
    // Se il piatto è eliminato, logga per debug ma non mostrarlo
    if (isDeleted) {
      console.warn(`⚠️ Piatto eliminato filtrato: ${dish.name} (ID: ${dish.id})`);
      return false;
    }
    
    return isActive && !isDeleted;
  });
  
  console.log(`🔍 Dopo filtro eliminati: ${filtered.length} piatti`);

  if (this.selectedCategory !== 'all') {
    filtered = filtered.filter(d => d.category_id === this.selectedCategory);
  }

  if (this.dishSearchTerm) {
    const term = this.dishSearchTerm.toLowerCase();
    filtered = filtered.filter(d =>
      d.name.toLowerCase().includes(term) ||
      d.description?.toLowerCase().includes(term)
    );
  }

  return filtered;
}

