  private recalculateComandaTotal(comanda: Comanda): void {
    if (!comanda.order_items || comanda.order_items.length === 0) {
      comanda.total_amount = 0;
      return;
    }

    // Calcola dalla somma dei total_price
    const calculatedTotal = comanda.order_items.reduce((sum, item) => {
      // Usa total_price se esiste, altrimenti calcola unit_price * quantity
      const itemTotal = item.total_price || (item.unit_price * item.quantity);
      return sum + itemTotal;
    }, 0);

    comanda.total_amount = calculatedTotal;

    console.log(`💰 Comanda ${comanda.comanda_number} totale ricalcolato:`, calculatedTotal);
  }

  // ===== METODI PER QUANTITÀ =====
getComandaTotalQuantity(comanda?: Comanda | null): number {
  if (!comanda) return 0;  // gestisce undefined o null
  
  if (!comanda.order_items || comanda.order_items.length === 0) return 0;
  return comanda.order_items.reduce((total, item) => total + (item.quantity || 1), 0);
}

  // Metodo che RIUTILIZZA getComandaTotalQuantity
  getTotalePiattiTutteComande(): number {
    if (!this.orderHeader?.comande) return 0;
    
    let totale = 0;
    for (const comanda of this.orderHeader.comande) {
      totale += this.getComandaTotalQuantity(comanda);
    }
    return totale;
  }
  
