async saveOrder(): Promise<void> {
  try {
    // PRIMA CONTROLLO: Comande vuote
    const emptyComande = this.getEmptyComande();
    
    if (emptyComande.length > 0) {
      const comandeNumbers = emptyComande.map(c => c.comanda_number).join(', ');
      const confirmMessage = `Le seguenti comande sono vuote: ${comandeNumbers}. 
Se procedi, queste comande vuote verranno eliminate dal salvataggio. 
Vuoi continuare comunque?`;
      
      const userConfirmed = window.confirm(confirmMessage);
      if (!userConfirmed) {
        console.log('❌ Salvataggio annullato dall\'utente');
        return; // Interrompe il salvataggio
      }
      
      // Se l'utente conferma, rimuovi le comande vuote dal draft
      this.removeEmptyComandeFromDraft(emptyComande);
    }
    
    // Procedi con il salvataggio normale
    this.loadingService.start();
    this.isLoading = true;
    console.log('💾 Salvando ordine...');

      // 1. Salva tutto nel database
      const success = await this.saveAllToDatabase();

      if (success) {
        console.log('✅ Ordine salvato nel database');

        // 2. Ricarica l'ordine dal database
        if (this.draftOrder && !this.draftOrder.id.startsWith('draft-')) {
          const freshOrder = await this.orderHelper.loadFullOrder(this.draftOrder.id);
          if (freshOrder) {
            this.draftOrder = freshOrder;
            this.orderHeader = JSON.parse(JSON.stringify(freshOrder));

            // Aggiorna comanda corrente
            if (freshOrder.comande && freshOrder.comande.length > 0) {
              const lastComanda = freshOrder.comande
                .slice()
                .reverse()
                .find(c => c.status !== 'cancelled');
              this.currentComanda = lastComanda || freshOrder.comande[0];
            }
          }
        }

        // 3. Notifica il parent
        this.saved.emit(this.orderHeader!);

        // 4. Reset stato locale
        this.localChanges = [];
        this.hasUnsavedChanges = false;

        console.log('🎉 Ordine salvato con successo');

      } else {
        console.error('❌ Errore durante il salvataggio');
        alert('Errore durante il salvataggio dell\'ordine');
      }

    } catch (error: any) {
      console.error('❌ Errore salvataggio ordine:', error);
      alert('Errore durante il salvataggio: ' + error.message);
    } finally {
      this.loadingService.stop();
      this.isLoading = false;
    }
  }

private removeEmptyComandeFromDraft(emptyComande: Comanda[]): void {
  if (!this.draftOrder?.comande) return;
  
  console.log('🗑️ Rimozione comande vuote dal draft:', 
    emptyComande.map(c => c.comanda_number));
  
  // Filtra via le comande vuote
  this.draftOrder.comande = this.draftOrder.comande.filter(comanda => 
    !emptyComande.some(empty => empty.id === comanda.id)
  );
  
  // Aggiorna UI
  this.updateOrderHeader();
  
  // Se la comanda corrente era vuota, cambia a un'altra
  if (this.currentComanda && emptyComande.some(c => c.id === this.currentComanda!.id)) {
    const firstNonEmpty = this.draftOrder.comande.find(c => 
      c.order_items && c.order_items.length > 0
    );
    this.currentComanda = firstNonEmpty || (this.draftOrder.comande[0] || null);
  }
  
  // Rimuovi dalle localChanges le modifiche relative a queste comande
  this.localChanges = this.localChanges.filter(change => {
    // Se è una nuova comanda vuota, rimuovila
    if (change.type === 'new_comanda' && 
        emptyComande.some(c => c.id === change.data.id)) {
      return false;
    }
    
    // Se è un'aggiunta a una comanda che ora è vuota, rimuovila
    if (change.type === 'add' && 
        emptyComande.some(c => c.id === change.data.order_id)) {
      return false;
    }
    
    return true;
  });
  
  console.log('✅ Comande vuote rimosse dal draft');
}

