  // ===== METODI PER MENU =====
  get dedicatedMenu(): any | null {
    return this.activeMenus.find(menu => menu.type === 'dedicated') || null;
  }

  get globalMenus(): any[] {
    return this.activeMenus.filter(menu => menu.type === 'global');
  }

  hasMenusToShow(): boolean {
    return this.activeMenus.length > 0;
  }

  hasDedicatedMenu(): boolean {
    return this.activeMenus.some(menu => menu.type === 'dedicated');
  }

  hasGlobalMenus(): boolean {
    return this.activeMenus.some(menu => menu.type === 'global');
  }

  // ===== METODI PER CAMBIO MODALITÀ =====
  switchToEditMode(): void {
    this.closeRequested.emit();
    // Il parent controller dovrebbe gestire il cambio di modalità
  }

  private updateOrderHeader(): void {
    if (!this.draftOrder) return;

    // ✅ FAI PUNTARE orderHeader.comande ALLA STESSA REFERENCE di draftOrder.comande
    this.orderHeader = {
      ...this.draftOrder,
      comande: this.draftOrder.comande // Stessa reference, non copiare!
    };
  }

  trackByOrderItemId(index: number, item: OrderItem): string {
    return item.id;
  }

  get comandaItemsCount(): number {
    return this.currentComanda?.order_items?.length || 0;
  }

  get totaleTavolata(): number {
    if (!this.orderHeader || !this.orderHeader.comande) return 0;
    return this.orderHeader.comande.reduce((total, comanda) => {
      return total + (comanda.total_amount || 0);
    }, 0);
  }

  /**
 * Verifica se una comanda può essere modificata
 */
isComandaEditable(comanda?: Comanda): boolean {
  const target = comanda || this.currentComanda;
  if (!target) return true; // Se non c'è comanda, permetto di creare
  
  // Stati che permettono modifiche
  const editableStatuses = ['ordered', 'waiting', 'draft'];
  
  return editableStatuses.includes(target.status);
}

/**
 * Verifica se un piatto può essere modificato
 */
isItemEditable(item: OrderItem): boolean {
  // Stati che permettono modifiche
  const editableStatuses = ['ordered', 'waiting', 'draft'];
  
  return editableStatuses.includes(item.status);
}

/**
 * Verifica se si possono aggiungere nuovi piatti alla comanda corrente
 */
canAddItemsToCurrentComanda(): boolean {
  if (!this.currentComanda) return true; // Se non c'è comanda, ne creeremo una nuova
  
  return this.isComandaEditable(this.currentComanda);
}


private getEmptyComande(): Comanda[] {
  if (!this.draftOrder?.comande) return [];
  
  return this.draftOrder.comande.filter(comanda => {
    // Una comanda è vuota se non ha items o l'array è vuoto
    return !comanda.order_items || comanda.order_items.length === 0;
  });
}

ngAfterViewInit(): void {
  if (this.tutorialService.currentStepData()?.id === 'order-editor') {
    // Attende il completamento dell'animazione (es. 300ms) e poi tenta
    setTimeout(() => {
      this.tutorialService.refreshTooltip();
      // Secondo tentativo dopo un altro piccolo ritardo (per sicurezza)
      setTimeout(() => this.tutorialService.refreshTooltip(), 200);
    }, 400); // Puoi regolare questo valore in base alla durata dell'animazione
  }
}

get hasMultipleComande(): boolean {
  return (this.orderHeader?.comande?.length ?? 0) > 1;
}

toggleComandaPage(): void {
  const wasShowingComanda = this.showComandaPage; // stato prima del toggle
  // Invertiamo il flag
  this.showComandaPage = !this.showComandaPage;

  // Se stavamo mostrando la pagina comanda (quindi ora passiamo alla pagina piatti)
  // e la selezione era "Tutte le comande", reimposta sulla prima comanda disponibile
  if (wasShowingComanda && this.currentComandaId === 'all') {
    const firstComanda = this.orderHeader?.comande?.find(c => c.status !== 'cancelled') 
                      || this.orderHeader?.comande?.[0];
    if (firstComanda) {
      this.switchComanda(firstComanda.id);
    }
  }
}


/**
 * Avvia lo spostamento di un item
 */
startMoveItem(item: OrderItem, fromComandaId: string): void {
  this.movingItem = { item, fromComandaId };
}

/**
 * Annulla lo spostamento
 */
cancelMove(): void {
  this.movingItem = null;
}

/**
 * Esegue lo spostamento verso la comanda di destinazione
 */
async executeMove(toComandaId: string): Promise<void> {
  if (!this.movingItem) return;
  const { item, fromComandaId } = this.movingItem;

  // Trova le comande di origine e destinazione
  const fromComanda = this.orderHeader?.comande?.find(c => c.id === fromComandaId);
  const toComanda = this.orderHeader?.comande?.find(c => c.id === toComandaId);
  if (!fromComanda || !toComanda) return;

  // Rimuovi l'item dalla comanda di origine
  const itemIndex = fromComanda.order_items?.findIndex(i => i.id === item.id) ?? -1;
  if (itemIndex === -1) return;
  fromComanda.order_items?.splice(itemIndex, 1);
  this.recalculateComandaTotal(fromComanda);

  // Crea un nuovo item per la comanda di destinazione (copiando i dati)
  const newItem: OrderItem = {
    ...item,
    id: 'draft-item-' + Date.now() + '-' + Math.random().toString(36).substr(2, 5), // nuovo ID univoco
    order_id: toComanda.id,
    comanda_id: toComanda.id,
  };
  if (!toComanda.order_items) toComanda.order_items = [];
  toComanda.order_items.push(newItem);
  this.recalculateComandaTotal(toComanda);

  // Aggiorna il totale generale dell'orderHeader
  if (this.orderHeader) {
    this.orderHeader.total_amount = this.orderHeader.comande?.reduce(
      (sum, c) => sum + (c.total_amount || 0), 0
    ) || 0;
  }

  // Registra la modifica (opzionale, per tenere traccia)
  this.localChanges.push({
    type: 'update',
    data: { moved: item.id, from: fromComandaId, to: toComandaId },
    timestamp: new Date()
  });
  this.hasUnsavedChanges = true;

  // Pulisci lo stato e forza l'aggiornamento della UI
  this.movingItem = null;
  this.cdr.markForCheck();
}

/**
 * Restituisce le comande diverse da quella corrente (per il select)
 */
getOtherComandas(currentComandaId: string): Comanda[] {
  return this.orderHeader?.comande?.filter(c => c.id !== currentComandaId) || [];
}

