// order-manager.service.ts
import { Injectable, inject } from '@angular/core';
import { SupabaseService } from '../Base/supabase.service';
import { AuthService } from '../Base/auth.service';
import { LoadingService } from '../Base/loading.service';
import { Comanda, OrderHeader, OrderItem, OrderStatus } from '../../models';

@Injectable({ providedIn: 'root' })
export class OrderManagerService {
  private supabase = inject(SupabaseService).getSupabaseClient();
  private authService = inject(AuthService);
  private loadingService = inject(LoadingService);

  // 📌 OCCUPA TAVOLO (crea tavolata con prima comanda)
  async occupyTable(tableId: string, customerName?: string): Promise<OrderHeader | null> {
    try {
      this.loadingService.start();
      
      const restaurantId = await this.authService.getCurrentRestaurantId();
      if (!restaurantId) return null;

      // 1. Crea order_header (tavolata)
      const orderNumber = await this.generateOrderNumber(restaurantId);
      
      const { data: orderHeader, error } = await this.supabase
        .from('order_headers')
        .insert({
          restaurant_id: restaurantId,
          table_id: tableId,
          order_number: orderNumber,
          status: 'active',
          customer_name: customerName || 'Cliente',
          total_amount: 0
        })
        .select()
        .single();

      if (error) throw error;

      // 2. Crea automaticamente la prima comanda (comanda_number = 1)
      const comanda = await this.createComanda(orderHeader.id);
      
      // 3. Carica la tavolata completa
      return await this.loadTavolata(orderHeader.id);
      
    } catch (error) {
      console.error('❌ Errore occupazione tavolo:', error);
      return null;
    } finally {
      this.loadingService.stop();
    }
  }

  // 📌 CREA NUOVA COMANDA
async createComanda(orderHeaderId: string): Promise<Comanda | null> {
  try {
    this.loadingService.start();
    
    const restaurantId = await this.authService.getCurrentRestaurantId();
    if (!restaurantId) return null;

    // 1. Ottieni dati della tavolata (INCLUDI customer_name)
    const { data: orderHeader, error: headerError } = await this.supabase
      .from('order_headers')
      .select('table_id, order_number, customer_name, status')
      .eq('id', orderHeaderId)
      .single();

    if (headerError) throw headerError;

    // 2. Calcola prossimo numero comanda
    const comandaNumber = await this.getNextComandaNumber(orderHeaderId);
    
    // 3. Genera numero univoco comanda
    const comandaOrderNumber = `${orderHeader.order_number}-${comandaNumber}`;

    // 4. Crea comanda
    const { data: comanda, error } = await this.supabase
      .from('comande')
      .insert({
        restaurant_id: restaurantId,
        order_header_id: orderHeaderId,
        comanda_number: comandaNumber,
        order_number: comandaOrderNumber,
        status: 'ordered',
        table_id: orderHeader.table_id,
        order_type: 'dine_in',
        subtotal: 0,
        tax_amount: 0,
        discount_amount: 0,
        total_amount: 0,
        customer_name: orderHeader.customer_name || 'Cliente' // Aggiunto valore di default
      })
      .select()
      .single();

    if (error) throw error;
    return comanda;
  } catch (error) {
    console.error('❌ Errore creazione comanda:', error);
    return null;
  } finally {
    this.loadingService.stop();
  }
}


  // 📌 AGGIUNGI PIATTO A COMANDA
  async addItemToComanda(
    comandaId: string,
    dishId: string,
    quantity: number = 1,
    notes: string = ''
  ): Promise<OrderItem | null> {
    try {
      this.loadingService.start();
      
      const restaurantId = await this.authService.getCurrentRestaurantId();
      if (!restaurantId) return null;

      // 1. Ottieni prezzo del piatto
      const { data: dish, error: dishError } = await this.supabase
        .from('dishes')
        .select('base_price, name')
        .eq('id', dishId)
        .single();

      if (dishError) throw dishError;

      // 2. Crea order item
      const totalPrice = dish.base_price * quantity;
      
      const { data: orderItem, error } = await this.supabase
        .from('order_items')
        .insert({
          order_id: comandaId,
          dish_id: dishId,
          quantity: quantity,
          unit_price: dish.base_price,
          total_price: totalPrice,
          item_notes: notes,
          status: 'ordered',
          restaurant_id: restaurantId
        })
        .select()
        .single();

      if (error) throw error;

      // 3. Aggiorna totale comanda
      await this.updateComandaTotal(comandaId);
      
      // 4. Aggiungi nome del piatto per comodità
      return {
        ...orderItem,
        dish_name: dish.name
      } as OrderItem;
    } catch (error) {
      console.error('❌ Errore aggiunta piatto:', error);
      return null;
    } finally {
      this.loadingService.stop();
    }
  }

  // 📌 CARICA TUTTA LA TAVOLATA
  async loadTavolata(orderHeaderId: string): Promise<OrderHeader | null> {
    try {
      this.loadingService.start();
      
      const { data, error } = await this.supabase
        .from('order_headers')
        .select(`
          *,
          comande (
            *,
            order_items (
              *,
              dish:dish_id (
                id,
                name,
                base_price,
                category_id
              )
            )
          )
        `)
        .eq('id', orderHeaderId)
        .single();

      if (error) throw error;
      return data;
    } catch (error) {
      console.error('❌ Errore caricamento tavolata:', error);
      return null;
    } finally {
      this.loadingService.stop();
    }
  }

  // 📌 CARICA TAVOLATA ATTIVA PER TAVOLO
  async getActiveTavolataByTable(tableId: string): Promise<OrderHeader | null> {
    try {
      const restaurantId = await this.authService.getCurrentRestaurantId();
      if (!restaurantId) return null;

      const { data, error } = await this.supabase
        .from('order_headers')
        .select(`
          *,
          comande (
            *,
            order_items (
              *,
              dish:dish_id (
                id,
                name,
                base_price
              )
            )
          )
        `)
        .eq('restaurant_id', restaurantId)
        .eq('table_id', tableId)
        .eq('status', 'active')
        .order('created_at', { ascending: false })
        .limit(1)
        .single();

      if (error) {
        if (error.code === 'PGRST116') return null; // Nessun risultato
        throw error;
      }
      return data;
    } catch (error) {
      console.error('❌ Errore caricamento tavolata attiva:', error);
      return null;
    }
  }

  // 📌 AGGIORNA STATO COMANDA
  async updateComandaStatus(comandaId: string, status: OrderStatus): Promise<boolean> {
    try {
      const { error } = await this.supabase
        .from('comande')
        .update({ 
          status,
          updated_at: new Date().toISOString()
        })
        .eq('id', comandaId);

      return !error;
    } catch (error) {
      console.error('❌ Errore aggiornamento stato comanda:', error);
      return false;
    }
  }

  // 📌 AGGIORNA QUANTITÀ PIATTO
  async updateItemQuantity(itemId: string, quantity: number): Promise<boolean> {
    try {
      // 1. Ottieni unit_price
      const { data: item, error: fetchError } = await this.supabase
        .from('order_items')
        .select('unit_price, order_id')
        .eq('id', itemId)
        .single();

      if (fetchError) throw fetchError;

      const totalPrice = item.unit_price * quantity;

      // 2. Aggiorna quantità e totale
      const { error } = await this.supabase
        .from('order_items')
        .update({
          quantity,
          total_price: totalPrice,
          updated_at: new Date().toISOString()
        })
        .eq('id', itemId);

      if (error) throw error;

      // 3. Aggiorna totale comanda
      if (item.order_id) {
        await this.updateComandaTotal(item.order_id);
      }

      return true;
    } catch (error) {
      console.error('❌ Errore aggiornamento quantità:', error);
      return false;
    }
  }

  // 📌 RIMUOVI PIATTO
  async removeItem(itemId: string): Promise<boolean> {
    try {
      // 1. Ottieni order_id prima di eliminare
      const { data: item, error: fetchError } = await this.supabase
        .from('order_items')
        .select('order_id')
        .eq('id', itemId)
        .single();

      if (fetchError) throw fetchError;

      // 2. Elimina item
      const { error } = await this.supabase
        .from('order_items')
        .delete()
        .eq('id', itemId);

      if (error) throw error;

      // 3. Aggiorna totale comanda
      if (item.order_id) {
        await this.updateComandaTotal(item.order_id);
      }

      return true;
    } catch (error) {
      console.error('❌ Errore rimozione piatto:', error);
      return false;
    }
  }

  // 📌 CHIUDI TAVOLATA
  async closeTavolata(orderHeaderId: string): Promise<boolean> {
    try {
      const { error } = await this.supabase
        .from('order_headers')
        .update({ 
          status: 'completed',
          updated_at: new Date().toISOString()
        })
        .eq('id', orderHeaderId);

      return !error;
    } catch (error) {
      console.error('❌ Errore chiusura tavolata:', error);
      return false;
    }
  }

  // 🔧 METODI PRIVATI
  private async generateOrderNumber(restaurantId: string): Promise<string> {
    const date = new Date();
    const year = date.getFullYear().toString().slice(-2);
    const month = (date.getMonth() + 1).toString().padStart(2, '0');
    const day = date.getDate().toString().padStart(2, '0');
    
    const { count } = await this.supabase
      .from('order_headers')
      .select('*', { count: 'exact', head: true })
      .eq('restaurant_id', restaurantId)
      .gte('created_at', `${date.getFullYear()}-${month}-${day}T00:00:00`)
      .lte('created_at', `${date.getFullYear()}-${month}-${day}T23:59:59`);

    const dailyCount = (count || 0) + 1;
    return `TAV-${year}${month}${day}-${dailyCount.toString().padStart(3, '0')}`;
  }

  private async getNextComandaNumber(orderHeaderId: string): Promise<number> {
    const { data, error } = await this.supabase
      .from('comande')
      .select('comanda_number')
      .eq('order_header_id', orderHeaderId)
      .order('comanda_number', { ascending: false })
      .limit(1);

    if (error) {
      console.error('Errore calcolo prossima comanda:', error);
      return 1;
    }
    return data && data.length > 0 ? data[0].comanda_number + 1 : 1;
  }

  private async updateComandaTotal(comandaId: string): Promise<void> {
    try {
      // Calcola somma degli order_items
      const { data: items, error } = await this.supabase
        .from('order_items')
        .select('total_price')
        .eq('order_id', comandaId);

      if (error) throw error;

      const total = (items || []).reduce(
        (sum, item) => sum + (item.total_price || 0),
        0
      );

      // Aggiorna comanda
      await this.supabase
        .from('comande')
        .update({ 
          total_amount: total,
          subtotal: total,
          updated_at: new Date().toISOString()
        })
        .eq('id', comandaId);
    } catch (error) {
      console.error('Errore aggiornamento totale comanda:', error);
    }
  }
}