// table-map.component.ts - VERSIONE SEMPLIFICATA
import { Component, OnInit, OnDestroy, inject, ViewChild, ElementRef, ChangeDetectorRef, HostBinding, effect, NgZone } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Subscription, interval } from 'rxjs';

// SERVIZI ESSENZIALI
import { OrderHeaderService } from '../../../services/Ordini/order-header.service';
import { LoadingService } from '../../../services/Base/loading.service';
import { TableService } from '../../../services/Tavoli/table.service';
import { FloorPlanService } from '../../../services/Mappa/floorplan.service';
import { ReservationService } from '../../../services/Prenotazioni/reservation.service';
import { AuthService } from '../../../services/Base/auth.service';
import { ShiftService } from '../../../services/shift.service';

// ALTRI SERVIZI
import { TableStatusService } from '../../../services/Tavoli/table-status.service';
import { FloorManagementService } from '../../../services/Mappa/floor-management.service';

// MODELS
import { Dish, FloorPlan, TableStatus, Table, Reservation } from '../../../models';

// COMPONENTI
import { OrderEditor } from './order-editor/order-editor';
import { ComandaService } from '../../../services/Ordini/comanda.service';
import { OrderItemService } from '../../../services/Ordini/order-item.service';
import { OrderManagerService } from '../../../services/Ordini/order-manager.service';
import { LucideAngularModule } from 'lucide-angular';
import { TutorialService } from '../../../services/tutorial.service';

interface OrderEditorData {
  table: Table;
  mode: 'edit' | 'view';
  existingOrderHeader: any | null;
  orderHeaders: any[];
  currentTavolataId: string | null;
  selectedComandaId?: string;
  reservation?: Reservation | null;
}

@Component({
  selector: 'app-table-map',
  templateUrl: './table-map.html',
  styleUrls: ['./table-map.css'],
  standalone: true,
  imports: [CommonModule, FormsModule, OrderEditor, LucideAngularModule]
})
export class TableMap implements OnInit, OnDestroy {
  // SERVIZI
  private tableStatusService = inject(TableStatusService);
  private floorManagementService = inject(FloorManagementService);
  private loadingService = inject(LoadingService);
  private tableService = inject(TableService);
  private floorPlanService = inject(FloorPlanService);
  private reservationService = inject(ReservationService);
  private authService = inject(AuthService);
  private orderHeaderService = inject(OrderHeaderService);
  private shiftService = inject(ShiftService);
  private comandaService = inject(ComandaService);
  private orderItemService = inject(OrderItemService);
  private orderManagerService = inject(OrderManagerService);
  private cdr = inject(ChangeDetectorRef);
  private elementRef = inject(ElementRef);
  private tutorialService = inject(TutorialService);
  private tutorialEditorOpened = false;
  private pendingTutorialStep: string | null = null;
  private ngZone = inject(NgZone);

  @ViewChild('mapCard', { static: false }) mapCardElement!: ElementRef;
  @ViewChild('tableMapContainer', { static: false }) tableMapContainer!: ElementRef;

  // STATI LOCALI
  zoomLevel = 1.0;
  minZoom = 0.5;
  maxZoom = 3.0;
  mobileView = false;
  isFullscreen = false;
  isLargeText = false;

  // FILTRI
  searchTerm = '';
  statusFilter = 'all';

  // MODALI (SOLO QUELLE ESSENZIALI)
  showQuickActionsModal = false;
  showManualReservationModal = false;
  showEditReservationModal = false;
  showAssignReservationModal = false;
  showTableReservationsModal = false;
  showTableAssignmentModal = false;

  // ORDER EDITOR
  showOrderEditorModal = false;
  showOrderEditorViewModal = false;
  orderEditorData: OrderEditorData = {
    table: null!,
    mode: 'edit',
    existingOrderHeader: null,
    orderHeaders: [],
    currentTavolataId: null,
    selectedComandaId: undefined
  };

  // DATI
  currentFloorPlan: FloorPlan | null = null;
  tableStatuses: TableStatus[] = [];
  selectedTable: Table | null = null;
  selectedTableStatus: TableStatus | null = null;
  currentRestaurant: any | null = null;
  private tableOrderCounts = new Map<string, number>();

  // FORM PRENOTAZIONE
  manualReservationData = {
    customer_name: '',
    customer_phone: '',
    reservation_date: '',
    reservation_time: '',
    party_size: 2,
    special_requests: ''
  };

  editingReservation: any = null;

  // TURNI
  orderingStatus: {
    allowed: boolean;
    reason: string;
    currentShift: any | null;
  } = {
      allowed: false,
      reason: 'Caricamento...',
      currentShift: null
    };

  // PRENOTAZIONI
  availableReservationsWithoutTable: any[] = [];
  selectedReservationForAssignment: any = null;
  assignmentReservation: any = null;
  suggestedTablesByFloorPlan: { [floorPlanId: string]: any[] } = {};
  selectedFloorPlanForAssignment: string | null = null;

  // RESERVATIONS PER TAVOLO
  selectedTableReservations = {
    active: null as any,
    futureReservations: [] as any[],
    shiftInfo: { current: null as any, next: null as any }
  };

  private subscriptions = new Subscription();

  constructor() {
effect(() => {
  const step = this.tutorialService.currentStepData();
  if (step?.id === 'order-editor' && !this.tutorialEditorOpened) {
    if (this.tableService.data.length === 0) {
      this.pendingTutorialStep = 'order-editor';
    } else {
      // Usa Promise.resolve().then() invece di setTimeout
      Promise.resolve().then(() => {
        this.openOrderEditorForTutorial();
      });
    }
  } else if (step?.id !== 'order-editor') {
    this.tutorialEditorOpened = false;
    this.pendingTutorialStep = null;
  }
});

  }

private openOrderEditorForTutorial(): void {
  const firstTable = this.tableService.data[0];
  if (!firstTable) {
    console.warn('[Tutorial] Nessun tavolo disponibile, passo allo step successivo');
    this.tutorialService.nextStep();
    return;
  }
  this.orderEditorData = {
    table: firstTable,
    mode: 'edit',
    existingOrderHeader: null,
    orderHeaders: [],
    currentTavolataId: null,
    selectedComandaId: undefined
  };
  this.showOrderEditorModal = true;
  console.log('[Tutorial] showOrderEditorModal impostato a true', this.showOrderEditorModal); // AGGIUNTO
}

  // GETTER PER COMPATIBILITÀ
  get floorPlans(): FloorPlan[] {
    return this.floorPlanService.data;
  }

  get dishes(): Dish[] {
    return [];
  }

  async ngOnInit() {
    await this.loadInitialData();
    this.checkMobileView();
    window.addEventListener('resize', () => this.checkMobileView());
    this.startShiftChecking();
    this.setupFullscreenListeners();
  }

  ngOnDestroy() {
    this.subscriptions.unsubscribe();
    window.removeEventListener('resize', () => this.checkMobileView());
    document.removeEventListener('fullscreenchange', this.handleFullscreenChange.bind(this));
    document.removeEventListener('webkitfullscreenchange', this.handleFullscreenChange.bind(this));
    document.removeEventListener('msfullscreenchange', this.handleFullscreenChange.bind(this));

  }

  // ============ CARICAMENTO DATI ============
  async loadInitialData(): Promise<void> {
    this.loadingService.start();

    try {
      await Promise.all([
        this.floorPlanService.loadFloorPlans(),
        this.tableService.loadData(),
        this.floorManagementService.loadTodaysReservations(),
      ]);

      const allVisibleTables = this.tableService.data.filter(t =>
        !t.is_merged || t.parent_table_id === null
      );

      this.tableStatuses = await this.tableStatusService.calculateTableStatus(allVisibleTables);

      if (this.floorPlans.length > 0 && !this.currentFloorPlan) {
        this.currentFloorPlan = this.floorPlans[0];
        await this.loadTablesForFloorPlan();
      }

      // TUTORIAL
if (this.pendingTutorialStep === 'order-editor' && !this.tutorialEditorOpened) {
  Promise.resolve().then(() => {
    this.openOrderEditorForTutorial();
  });
}
    } finally {
      this.loadingService.stop();
    }
  }


  // ============ INTERAZIONI TAVOLO ============
  async onTableClick(tableStatus: TableStatus) {
    this.selectedTable = tableStatus.table;
    this.selectedTableStatus = tableStatus;
    await this.loadTableReservations(tableStatus.table.id);
    this.showQuickActionsModal = true;
  }

  deselectTable() {
    this.selectedTable = null;
    this.selectedTableStatus = null;
    this.showQuickActionsModal = false;
    this.showManualReservationModal = false;
    this.showEditReservationModal = false;
  }

  // ============ GESTIONE PRENOTAZIONI ============
  async openManualReservationModal() {
    if (!this.selectedTable) return;

    const now = new Date();
    this.manualReservationData = {
      customer_name: '',
      customer_phone: '',
      reservation_date: now.toISOString().split('T')[0],
      reservation_time: now.toTimeString().split(' ')[0].substring(0, 5),
      party_size: this.selectedTable.capacity || 2,
      special_requests: ''
    };

    this.showQuickActionsModal = false;
    this.showManualReservationModal = true;
  }

  closeManualReservationModal() {
    this.showManualReservationModal = false;
  }

  async createManualReservation() {
    if (!this.selectedTable) return;

    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return;

      const reservationData = {
        restaurant_id: restaurantId,
        table_id: this.selectedTable.id,
        reservation_date: this.manualReservationData.reservation_date,
        reservation_time: this.manualReservationData.reservation_time,
        party_size: this.manualReservationData.party_size,
        special_requests: this.manualReservationData.special_requests,
        status: 'confirmed' as const,
        customer_name: this.manualReservationData.customer_name,
        customer_phone: this.manualReservationData.customer_phone
      };

      const result = await this.reservationService.createRestaurantReservation(reservationData);

      if (result) {
        this.closeManualReservationModal();
        await this.loadInitialData();
        alert('Prenotazione creata con successo!');
      } else {
        alert('Errore nella creazione della prenotazione');
      }
    } catch (error) {
      console.error('Error creating manual reservation:', error);
      alert('Errore durante la creazione della prenotazione: ' + (error as any).message);
    }
  }

  // ============ GESTIONE ORDINI (SEMPLICE) ============
  async openOrderEditor(): Promise<void> {
    if (!this.selectedTable) return;

    try {
      this.loadingService.start();

      // Cerca se esiste già un order header attivo
      const activeOrderHeader = await this.orderHeaderService.getActiveByTable(this.selectedTable.id);

      if (activeOrderHeader) {
        // Se esiste, apri in modalità VIEW per vedere gli ordini esistenti
        this.orderEditorData = {
          table: this.selectedTable,
          mode: 'view',
          existingOrderHeader: activeOrderHeader,
          orderHeaders: [activeOrderHeader],
          currentTavolataId: activeOrderHeader.id,
          selectedComandaId: undefined  // Aggiungi questa riga
        };
        this.showOrderEditorViewModal = true;
        console.log('👁️ Apro order editor in modalità VIEW');
      } else {
        // Se non esiste, apri in modalità EDIT per crearne uno nuovo
        this.orderEditorData = {
          table: this.selectedTable,
          mode: 'edit',
          existingOrderHeader: null,
          orderHeaders: [],
          currentTavolataId: null,
          selectedComandaId: undefined  // Aggiungi questa riga
        };
        this.showOrderEditorModal = true;
        console.log('✏️ Apro order editor in modalità EDIT (nuovo)');
      }

      this.showQuickActionsModal = false;

    } catch (error: any) {
      console.error('❌ Errore apertura order editor:', error);
    } finally {
      this.loadingService.stop();
    }
  }




  closeOrderEditorModal(): void {
    this.showOrderEditorModal = false;
    this.loadTablesForFloorPlan(); // Ricarica per aggiornare lo stato
  }

  closeOrderEditorViewModal(): void {
    this.showOrderEditorViewModal = false;
  }

  // ============ UTILITY ============
  private async loadTableReservations(tableId: string): Promise<void> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return;

      const today = new Date().toISOString().split('T')[0];
      const reservations = this.reservationService.data.filter(reservation =>
        reservation.restaurant_id === restaurantId &&
        reservation.table_id === tableId &&
        reservation.reservation_date === today &&
        ['confirmed', 'pending'].includes(reservation.status)
      ).sort((a, b) => a.reservation_time.localeCompare(b.reservation_time));

      // Separazione logica semplificata
      let activeReservation = null;
      const futureReservations = [];

      for (const reservation of reservations) {
        const reservationTime = new Date(`${reservation.reservation_date}T${reservation.reservation_time}`);
        const now = new Date();
        const timeDiffHours = (reservationTime.getTime() - now.getTime()) / (1000 * 60 * 60);

        if (timeDiffHours >= 0 && timeDiffHours <= 1.5) {
          activeReservation = reservation;
        } else if (timeDiffHours > 1.5) {
          futureReservations.push(reservation);
        }
      }

      this.selectedTableReservations = {
        active: activeReservation,
        futureReservations: futureReservations,
        shiftInfo: { current: null, next: null }
      };

    } catch (error) {
      console.error('Errore caricamento prenotazioni tavolo:', error);
      this.selectedTableReservations = {
        active: null,
        futureReservations: [],
        shiftInfo: { current: null, next: null }
      };
    }
  }

  // ============ UI HELPERS ============
  private checkMobileView(): void {
    this.mobileView = window.innerWidth <= 768;
  }

  getFilteredTables(): TableStatus[] {
    let filtered = this.tableStatuses;

    if (this.statusFilter !== 'all') {
      filtered = filtered.filter(ts => ts.status === this.statusFilter);
    }

    if (this.searchTerm) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(ts =>
        ts.table.table_number.toLowerCase().includes(term) ||
        ts.table.table_name.toLowerCase().includes(term)
      );
    }

    return filtered;
  }

  getTableClass(tableStatus: TableStatus): string {
    const selected = this.selectedTable?.id === tableStatus.table.id;
    return `table-element shape-${tableStatus.table.shape} ${tableStatus.status} ${selected ? 'selected' : ''}`;
  }

  getTableStyle(table: Table) {
    return {
      left: table.position_x + 'px',
      top: table.position_y + 'px',
      width: table.width + 'px',
      height: table.height + 'px',
      'border-radius': table.shape === 'circle' ? '50%' : '0px',
      transform: `rotate(${table.rotation}deg)`
    };
  }

  // ============ TURNI ============
  private startShiftChecking(): void {
    this.checkCurrentShift();
    this.subscriptions.add(
      interval(60000).subscribe(() => this.checkCurrentShift())
    );
  }

  private async checkCurrentShift(): Promise<void> {
    const status = await this.shiftService.getOrderingStatus();
    this.orderingStatus = status;
  }

  getShiftStatusClass(): string {
    return this.orderingStatus.allowed ? 'shift-active' : 'shift-inactive';
  }

  getShiftStatusText(): string {
    return this.orderingStatus.allowed ? '📋 Orario di turno' : '⏰ ' + this.orderingStatus.reason;
  }

  // ============ RESTAURANT ID ============
  private async getCurrentRestaurantId(): Promise<string | null> {
    try {
      const staffId = this.authService.getCurrentStaffRestaurantId();
      if (staffId) return staffId;

      const user = this.authService.currentUserValue;
      if (!user) return null;

      await this.reservationService.loadData();
      if (this.reservationService.data.length > 0) {
        return this.reservationService.data[0]?.restaurant_id || null;
      }

      return null;
    } catch (error) {
      console.error('Errore in getCurrentRestaurantId:', error);
      return null;
    }
  }

  // ============ TEMPLATE HELPERS ============
  getStatusColorClass(status: string = ''): string {
    return `status-${status}`;
  }

  getStatusText(status: string = ''): string {
    const statusMap: { [key: string]: string } = {
      'free': 'Libero',
      'reserved': 'Prenotato',
      'occupied': 'Occupato'
    };
    return statusMap[status] || status;
  }

  // ============ CONTEGGI PIATTI ============
  async getTableOrderItemsCount(tableId: string): Promise<number> {
    try {
      // Versione semplificata: cerca order header e conta gli items
      const orderHeader = await this.orderHeaderService.getActiveByTable(tableId);
      if (!orderHeader) return 0;

      // Carica comande
      const comande = await this.comandaService.loadByOrderHeaderId(orderHeader.id);

      let totalItems = 0;
      for (const comanda of comande) {
        // Carica items per ogni comanda
        const items = await this.orderItemService.loadByComandaId(comanda.id);
        totalItems += items.length;
      }

      return totalItems;

    } catch (error) {
      console.error('Errore conteggio piatti:', error);
      return 0;
    }
  }




  // ============ METODI PER TAVOLO ============
  onFloorPlanSelect(plan: FloorPlan) {
    this.currentFloorPlan = plan;
    this.loadTablesForFloorPlan();
    this.deselectTable();
  }

  // ============ METODI PER FULLSCREEN ============
  async safeToggleFullscreen() {
    try {
      if (!document.fullscreenElement) {
        // Entra in fullscreen
        const element = this.tableMapContainer?.nativeElement || document.documentElement;

        // Forza l'aggiornamento della vista
        this.cdr.detectChanges();

        if (element.requestFullscreen) {
          await element.requestFullscreen();
        } else if ((element as any).webkitRequestFullscreen) {
          await (element as any).webkitRequestFullscreen();
        } else if ((element as any).msRequestFullscreen) {
          await (element as any).msRequestFullscreen();
        }

        this.isFullscreen = true;

      } else {
        // Esci dal fullscreen
        if (document.exitFullscreen) {
          await document.exitFullscreen();
        } else if ((document as any).webkitExitFullscreen) {
          await (document as any).webkitExitFullscreen();
        } else if ((document as any).msExitFullscreen) {
          await (document as any).msExitFullscreen();
        }

        this.isFullscreen = false;
      }

      // Forza l'aggiornamento della vista
      this.cdr.detectChanges();

    } catch (error) {
      console.error('Errore fullscreen:', error);
      this.isFullscreen = !this.isFullscreen;
      this.cdr.detectChanges();
    }
  }



  private setupFullscreenListeners() {
    document.addEventListener('fullscreenchange', this.handleFullscreenChange.bind(this));
    document.addEventListener('webkitfullscreenchange', this.handleFullscreenChange.bind(this));
    document.addEventListener('msfullscreenchange', this.handleFullscreenChange.bind(this));
  }

  private handleFullscreenChange() {
    const wasFullscreen = this.isFullscreen;

    this.isFullscreen = !!(
      document.fullscreenElement ||
      (document as any).webkitFullscreenElement ||
      (document as any).msFullscreenElement
    );


    // Forza l'aggiornamento della vista
    setTimeout(() => {
      this.cdr.detectChanges();
    }, 0);
  }


  // ============ METODI PER ZOOM ============
  zoomIn() { this.zoomLevel = Math.min(this.zoomLevel * 1.25, this.maxZoom); }
  zoomOut() { this.zoomLevel = Math.max(this.zoomLevel / 1.25, this.minZoom); }
  resetZoom() { this.zoomLevel = 1.0; }

  getScaledWidth(): number { return (this.currentFloorPlan?.width || 1000) * this.zoomLevel; }
  getScaledHeight(): number { return (this.currentFloorPlan?.height || 800) * this.zoomLevel; }

  // ============ METODI PRENOTAZIONI ============
  async updateReservation(): Promise<void> {
    if (this.editingReservation) {
      try {
        const success = await this.reservationService.updateReservation(
          this.editingReservation.id,
          this.editingReservation
        );

        if (success) {
          await this.loadInitialData();
          this.closeEditReservationModal();
          this.deselectTable();
        } else {
          alert('Errore durante l\'aggiornamento della prenotazione');
        }
      } catch (error) {
        console.error('Errore nell\'aggiornamento della prenotazione:', error);
        alert('Errore durante l\'aggiornamento della prenotazione');
      }
    }
  }

  async deleteReservation(): Promise<void> {
    if (this.editingReservation && this.isReservationDeletable(this.editingReservation)) {
      try {
        const success = await this.reservationService.deleteReservation(this.editingReservation.id);

        if (success) {
          await this.loadInitialData();
          this.closeEditReservationModal();
          this.deselectTable();
        } else {
          alert('Errore durante l\'eliminazione della prenotazione');
        }
      } catch (error) {
        console.error('Errore nell\'eliminazione della prenotazione:', error);
        alert('Errore durante l\'eliminazione della prenotazione');
      }
    } else {
      alert('Impossibile eliminare questa prenotazione');
    }
  }

  isReservationDeletable(reservation: any): boolean {
    if (!reservation?.reservation_date || !reservation?.reservation_time) return false;
    const reservationDateTime = new Date(`${reservation.reservation_date}T${reservation.reservation_time}`);
    const now = new Date();
    return reservationDateTime > now;
  }

  openEditReservationModal() {
    if (this.selectedTableStatus?.currentReservation) {
      this.editingReservation = { ...this.selectedTableStatus.currentReservation };
      this.showEditReservationModal = true;
      this.showQuickActionsModal = false;
    }
  }

  closeEditReservationModal() {
    this.showEditReservationModal = false;
    this.editingReservation = null;
  }

  // ============ METODI PER STATISTICHE ============
  getFreeTablesCount(): number {
    return this.tableStatuses.filter(ts => ts.status === 'free').length;
  }

  getReservedTablesCount(): number {
    return this.tableStatuses.filter(ts => ts.status === 'reserved').length;
  }

  getOccupiedTablesCount(): number {
    return this.tableStatuses.filter(ts => ts.status === 'occupied').length;
  }

  getTotalTablesCount(): number {
    return this.tableStatuses.length;
  }

  // ============ METODO toggleSize ============
  toggleSize(): void {
    this.isLargeText = !this.isLargeText;
  }

  // ============ METODO getTableOrderItemsCount (versione sync) ============
  getTableOrderItemsCountSync(tableId: string): number {
    // Se hai una mappa di conteggi, usala qui
    // Altrimenti, per ora restituisci 0
    return 0;
  }

  // Metodo per caricare tutti i conteggi
  async loadAllTableOrderCounts(): Promise<void> {
    this.tableOrderCounts.clear();

    const promises = this.tableStatuses.map(async tableStatus => {
      try {
        // Usa la nuova versione
        const count = await this.getTableOrderItemsCount(tableStatus.table.id);
        this.tableOrderCounts.set(tableStatus.table.id, count);
      } catch (error) {
        console.error(`Errore caricamento ordini per tavolo ${tableStatus.table.id}:`, error);
        this.tableOrderCounts.set(tableStatus.table.id, 0);
      }
    });

    await Promise.all(promises);
  }


  // Metodo sync per ottenere il conteggio
  getTableOrderCount(tableId: string): number {
    return this.tableOrderCounts.get(tableId) || 0;
  }

  // Modifica il metodo loadTablesForFloorPlan per caricare anche i conteggi
async loadTablesForFloorPlan() {
  if (!this.currentFloorPlan) return;

  // Usa il current_version della mappa, con fallback a 1
  const version = this.currentFloorPlan.current_version ?? 1;

  // Ottieni i tavoli filtrati per floor plan e versione
  const allTablesForPlan = this.tableService.getTablesByFloorPlan(
    this.currentFloorPlan.id,
    version
  );

  // Escludi i tavoli "merged" non principali
  const visibleTables = allTablesForPlan.filter(t => !t.is_merged || t.parent_table_id === null);

  // Ricalcola gli status
  this.tableStatuses = await this.tableStatusService.calculateTableStatus(visibleTables);

  // Ricarica i conteggi ordini (se necessario)
  await this.loadAllTableOrderCounts();
}

  // Aggiungi anche questo metodo per il conteggio tavoli con ordini
  getTablesWithOrdersCount(): number {
    return Array.from(this.tableOrderCounts.values()).filter(count => count > 0).length;
  }

  // ============ LIBERA TAVOLO ============
  async freeTable(): Promise<void> {
    if (!this.selectedTable) return;

    // ✅ SALVA IL RIFERIMENTO AL TAVOLO PRIMA CHE VENGA DESELEZIONATO
    const tableToFree = this.selectedTable;
    const tableNumber = tableToFree.table_number;

    try {
      // 1. Controlla se ci sono ordini attivi
      const orderCount = await this.getTableOrderItemsCount(tableToFree.id);

      if (orderCount > 0) {
        const confirmWithOrders = confirm(
          `⚠️ ATTENZIONE!\n\n` +
          `Il tavolo ${tableNumber} ha ${orderCount} piatti ordinati.\n\n` +
          `Sei sicuro di voler liberare il tavolo?\n` +
          `Questa azione chiuderà tutti gli ordini attivi.`
        );

        if (!confirmWithOrders) return;
      } else {
        const confirmFree = confirm(
          `Vuoi liberare il tavolo ${tableNumber}?`
        );

        if (!confirmFree) return;
      }

      // 2. Chiudi tutti gli order headers attivi
      this.loadingService.start();
      const success = await this.orderHeaderService.closeAllActiveHeadersForTable(
        tableToFree.id
      );

      if (success) {
        console.log(`✅ Tavolo ${tableNumber} liberato`);

        // 3. Aggiorna lo stato del tavolo
        await this.loadTablesForFloorPlan();

        // 4. Chiudi le modali e deseleziona
        this.deselectTable();

        // ✅ USA LA VARIABILE SALVATA
        alert(`✅ Tavolo ${tableNumber} liberato con successo!`);
      } else {
        alert('❌ Errore durante la liberazione del tavolo. Riprova.');
      }

    } catch (error) {
      console.error('❌ Errore liberazione tavolo:', error);
      alert('❌ Errore durante la liberazione del tavolo.');
    } finally {
      this.loadingService.stop();
    }
  }

  async addNewComandaToTable(): Promise<void> {
    if (!this.selectedTable) return;

    try {
      this.loadingService.start();

      console.log('🆕 Aggiunta nuova comanda al tavolo:', this.selectedTable.table_number);

      // 1. Cerca tavolata attiva per questo tavolo
      const activeOrderHeader = await this.orderHeaderService.getActiveByTable(this.selectedTable.id);

      if (!activeOrderHeader) {
        console.error('❌ Nessuna tavolata attiva trovata per questo tavolo');
        alert('Prima crea una tavolata per questo tavolo');
        return;
      }

      console.log('✅ Tavolata trovata:', activeOrderHeader.order_number);

      // 2. Usa OrderManagerService per creare nuova comanda
      const newComanda = await this.orderManagerService.createComanda(activeOrderHeader.id);

      if (!newComanda) {
        console.error('❌ Errore nella creazione della nuova comanda');
        alert('Errore nella creazione della nuova comanda');
        return;
      }

      console.log('✅ Nuova comanda creata:', newComanda.comanda_number);

      // 3. Ora dobbiamo aprire l'order-editor con questa nuova comanda
      // Ricarichiamo l'order header completo con tutte le comande
      const fullOrderHeader = await this.orderManagerService.loadTavolata(activeOrderHeader.id);

      if (!fullOrderHeader) {
        console.error('❌ Impossibile caricare l\'ordine completo');
        alert('Errore nel caricamento dell\'ordine');
        return;
      }

      // 4. Apri l'order-editor in modalità edit con la nuova comanda selezionata
      this.orderEditorData = {
        table: this.selectedTable,
        mode: 'edit',
        existingOrderHeader: fullOrderHeader,
        orderHeaders: [fullOrderHeader],
        currentTavolataId: fullOrderHeader.id,
        selectedComandaId: newComanda.id  // Questo deve essere presente
      };

      this.showOrderEditorModal = true;
      this.showQuickActionsModal = false;

      console.log('📋 Aperto order editor con nuova comanda:', newComanda.comanda_number);

    } catch (error: any) {
      console.error('💥 Errore in addNewComandaToTable:', error);
      alert('Errore: ' + error.message);
    } finally {
      this.loadingService.stop();
    }
  }


  onOrderSaved(updatedOrder: any): void {
    console.log('✅ Ordine salvato, aggiorno la mappa');

    // Ricarica lo stato dei tavoli per aggiornare la UI
    this.loadTablesForFloorPlan();

    // Chiudi i modali
    this.closeOrderEditorModal();
    this.closeOrderEditorViewModal();
  }

  get isLoading(): boolean {
    return this.loadingService.isLoadingSync();
  }

  @HostBinding('class.fullscreen-mode')
  get isFullscreenMode(): boolean {
    return this.isFullscreen;
  }


}