// table-status.service.ts - VERSIONE CORRETTA
import { Injectable } from '@angular/core';
import { Table, TableStatus, Comanda, OrderHeader } from '../../models';
import { BaseService } from '../Base/base.service';

@Injectable({ providedIn: 'root' })
export class TableStatusService extends BaseService<any> {
  protected override getTableName(): string {
    return 'tables';
  }

  // 🟢 CALCOLA STATO TAVOLO
  async calculateTableStatus(tables: Table[]): Promise<TableStatus[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return [];

      const tableIds = tables.map(t => t.id);
      const today = new Date().toISOString().split('T')[0];

      // 1. Ottieni order headers attivi per questi tavoli
      const { data: activeHeaders, error: headersError } = await this.supabaseService
        .getSupabaseClient()
        .from('order_headers')
        .select(`
          *,
          comande (*)
        `)
        .eq('restaurant_id', restaurantId)
        .eq('status', 'active')
        .in('table_id', tableIds);

      if (headersError) {
        console.error('Errore order headers:', headersError);
      }

      // 2. Ottieni prenotazioni di oggi
      const { data: reservations, error: resError } = await this.supabaseService
        .getSupabaseClient()
        .from('reservations')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('reservation_date', today)
        .in('status', ['confirmed', 'pending'])
        .in('table_id', tableIds);

      if (resError) console.error('Errore prenotazioni:', resError);

      // 3. Calcola stato per ogni tavolo
      return tables.map(table => {
        const tableActiveHeaders = (activeHeaders || []).filter((h: any) => h.table_id === table.id);
        const tableReservations = (reservations || []).filter((r: any) => r.table_id === table.id);

        let status: 'free' | 'reserved' | 'occupied' = 'free';
        let currentReservation = null;
        let currentOrders: Comanda[] = [];
        let tavolataId = null;

        if (tableActiveHeaders.length > 0) {
          status = 'occupied';
          tavolataId = tableActiveHeaders[0].id;
          
          // Raccogli tutte le comande degli order headers attivi
          tableActiveHeaders.forEach((header: any) => {
            if (header.comande && header.comande.length > 0) {
              // Converti i dati nel tipo corretto
              const comande = header.comande.map((comandaData: any) => ({
                ...comandaData,
                // Assicurati che i campi obbligatori siano presenti
                restaurant_id: comandaData.restaurant_id || restaurantId,
                order_header_id: comandaData.order_header_id || header.id,
                table_id: comandaData.table_id || table.id,
                subtotal: comandaData.subtotal || 0,
                tax_amount: comandaData.tax_amount || 0,
                discount_amount: comandaData.discount_amount || 0,
                total_amount: comandaData.total_amount || 0,
                created_at: comandaData.created_at,
                updated_at: comandaData.updated_at,
                // Campi opzionali con valori di default
                customer_name: comandaData.customer_name || null,
                customer_phone: comandaData.customer_phone || null,
                customer_notes: comandaData.customer_notes || null,
                order_type: comandaData.order_type || 'dine_in',
                status: comandaData.status || 'ordered'
              })) as Comanda[];
              
              currentOrders = currentOrders.concat(comande);
            }
          });
        } else if (tableReservations.length > 0) {
          status = 'reserved';
          currentReservation = tableReservations[0];
        }

        return {
          table,
          status,
          currentReservation,
          currentOrders,
          tavolataId
        } as TableStatus;
      });
    } catch (error) {
      console.error('❌ Errore calcolo stato tavoli:', error);
      return [];
    }
  }
}